import { useEffect } from "react"
import STORAGE, { setStorage } from "src/lib/storage"

const Receiver = () => {
  useEffect(() => {
    window.addEventListener("message", event => {
      if (event.origin === "https://tintuc.h2qsolution.com") {
        const { key, value } = event.data
        setStorage(STORAGE.REMEMBER_LOGIN, value)
        setStorage(STORAGE.TOKEN, value)
      }
    })

    // Gửi phản hồi ngược nếu cần
    // window.parent.postMessage(
    //   { status: "ok" },
    //   "https://tintuc.h2qsolution.com",
    // )
  }, [])

  return <></>
}

export default Receiver
